#include <stdio.h>
#define MOD 1000000007
int main() {
    int n, q;
    scanf("%d", &n);
    int xi[n], yi[n], ai[n];
    for (int i = 0; i < n; i++) {
        scanf("%d %d %d", &xi[i], &yi[i], &ai[i]);
    }
    scanf("%d", &q);
    while (q--) {
        int type;
        scanf("%d", &type);
        if (type == 1) {
            int x, y, l, r;
            scanf("%d %d %d %d", &x, &y, &l, &r);
            for (int i = l - 1; i < r; i++) {
                int angle = ai[i];
                if (angle == 90) {
                    int temp = x;
                    x = -y + xi[i];
                    y = temp + yi[i];
                } else if (angle == 180) {
                    x = -x + 2 * xi[i];
                    y = -y + 2 * yi[i];
                } else if (angle == 270) {
                    int temp = x;
                    x = y + xi[i];
                    y = -temp + yi[i];
                }
            }
            printf("%d %d\n", (x % MOD + MOD) % MOD, (y % MOD + MOD) % MOD);
        } else {
            int u, x, y, b;
            scanf("%d %d %d %d", &u, &x, &y, &b);
            xi[u - 1] = x;
            yi[u - 1] = y;
            ai[u - 1] = b;
        }
    }
    return 0;
}

